RISKS:
[
 {
  "riskId": "risk.competitive-foreclosure.framework-agreements-close-first-buyer",
  "title": "The declared 'large operators' beachhead is pre-signed: global framework agreements close the 40% buyer cell before the first sales call",
  "claim": "The venture's own profile names large operators as the first buyer, and the ledger prices that cell at 0.40 of PDU spend with a comfortable 0.33–0.47 band. But the band models uncertainty about SIZE, not AVAILABILITY. The procurement record shows large operators buying rack power through multi-year global framework agreements and all-in integrated contracts (the Digital Realty–Schneider $373M framework pattern; Iren's all-in Dell deal; Jülich bundling PDU into a single IT line item). A framework agreement is not a competitor to out-sell — it is a contract that removes the tender from the market for its whole term. If a majority of the 0.40 cell is framework-governed, the entrant's declared beachhead is contractually closed for exactly its Year-1 window, and the YAM is silently re-based onto the slower mid-market and channel cells.",
  "falsifier": "Two or more CE large operators (Equinix/NTT/Data4-class) issuing standalone, multi-vendor rack-PDU RFQs open to non-framework vendors within the next 12 months."
 },
 {
  "riskId": "risk.competitive-foreclosure.distributor-line-review-lockout",
  "title": "Annual line reviews plus Legrand's dual-brand grip close the distributor cell mid-cycle — the entrant arrives with the shelf already allocated",
  "claim": "The 0.13 distributor cell looks like the easy channel: no framework agreements, documented master-distributor models, even explicit private-label options for distributors in buyer's guides. But distribution in this category runs on annual line reviews with exclusivity and margin-program terms, and the intelligent-PDU shelf specifically is consolidated — Legrand owns BOTH Raritan and Server Technology, the two intelligent-PDU specialist brands, giving one vendor two slots on every line card and strong leverage in review negotiations. A pre-launch entrant hits the market mid-cycle: even a willing distributor cannot onboard a conflicting line until the next review, which lands at or after the end of the venture's Year-1 window. The cell is not small — for the YAM horizon it is closed.",
  "falsifier": "A named CE electrical/IT distributor (Rexel, Sonepar, Also-class) confirming in writing that a new intelligent-PDU line can be onboarded within two quarters without waiting for the annual line review or triggering an exclusivity conflict."
 },
 {
  "riskId": "risk.competitive-foreclosure.bundle-pricing-kills-bakeoffs",
  "title": "Near-zero-margin PDU bundling inside power+cooling packages means the contestable Year-1 pool is below the model's own 0.5% floor",
  "claim": "The obtainableFactor band (0.5–3%) assumes there exists a pool of standalone rack-PDU purchase decisions a new entrant can compete for. But the same incumbents sell the $23B power and $26B cooling packages those PDUs plug into, and the procurement record shows PDUs travelling as embedded line items inside those packages — where the incumbent can price the PDU at near-zero margin because the busway, UPS and cooling carry the deal. The only standalone PDU procurements surfaced by research were tiny ($58K–$130K), had 1–2 bidders, and one was explicitly sole-sourced. Meanwhile the 1%-of-SAM anchor itself is generic startup folklore: the sources define SOM as a 1–3 or 3–5 year cumulative window, and the closest worked hardware comparable runs at ~0.1% of SAM. Both legs of the 1% — the benchmark and the tender evidence — point below the band, not inside it.",
  "falsifier": "A logged pipeline of ≥5 standalone, multi-vendor rack-PDU tenders in CE-7, each ≥€250K, posted within any 6-month window, in which a non-incumbent vendor is qualified to bid."
 },
 {
  "riskId": "risk.competitive-foreclosure.oem-cell-two-sided-squeeze",
  "title": "The OEM/integrator cell is squeezed shut from both sides: brand-spec deals go to incumbent ecosystems, white-label seats go to scale ODMs",
  "claim": "The 0.22 OEM/integrator cell looks like the natural entry channel for an industrial entrant — and superficially the evidence agrees, because BOTH routes into it are documented: integrators buy branded PDUs, and buyer's guides advertise OEM/private-label options. The trap is that each route is closed for a different reason. Every integrator case study found shows selection of branded incumbents on certification, DCIM compatibility and support ecosystems — assets a Year-1 entrant does not have. The white-label seats, meanwhile, are held by Asian ODMs (the Digipower pattern) competing on a manufacturing cost curve a Central European industrial entrant cannot match. The cell's 0.22 value is an unsourced internal estimate with an addressability premise no source supports; for this venture the genuinely open fraction may be a third of the modeled cell.",
  "falsifier": "One CE rack integrator or OEM signing a design-in or white-label agreement with the entrant, or a documented integrator RFQ in which a non-incumbent, non-ODM intelligent PDU is evaluated on merit within the launch year."
 },
 {
  "riskId": "risk.competitive-foreclosure.intelligent-pdu-concentration-shrinks-serviceable",
  "title": "In the intelligent-PDU sub-market the venture actually plays in, Legrand's dual acquisition plus DCIM spec-lock makes concentration — and the serviceable haircut — worse than the headline",
  "claim": "shape.cr3 = 0.55 is computed for the whole rack-PDU category, and serviceableFactor's 0.55 haircut is justified purely on regulatory reach (EN 50600, ecodesign, CE/TÜV). Neither number describes the venture's actual product market: INTELLIGENT PDUs, where Legrand owns both specialist brands (Raritan and Server Technology), Vertiv holds Geist, and Schneider leads the category — so the intelligent sub-segment is materially more concentrated than the blended 0.55 suggests. Concentration in intelligent PDUs is not just competitive pressure; it is a serviceability constraint, because intelligent-PDU purchases are spec-locked to DCIM/monitoring ecosystems and vendor-certified compatibility lists. Demand written into specs as 'Raritan-compatible' or 'certified for our DCIM' is not reachable at any price. The 0.55 serviceableFactor, built only on regulatory logic, silently assumes all regulatory-clear demand is spec-open — the one assumption the sub-market's ownership structure contradicts.",
  "falsifier": "The Omdia rack-PDU vendor-share table showing intelligent-PDU top-3 combined share below ~50%, or ≥3 CE operator/colo PDU specifications requiring only open protocols (SNMP/Redfish/Modbus) with no vendor-certified DCIM compatibility list."
 }
]

Emit JSON: { items: [{riskId, queries: [{query, kind: confirming|falsifying|base-rate}]}] } — 3 queries per risk.
